# Unit Tests for `topological_sort`

```python
import pytest
from collections import defaultdict


def topological_sort(graph: dict) -> list:
    visited = set()
    result = []
    def dfs(node):
        if node in visited:
            return
        visited.add(node)
        for neighbor in graph.get(node, []):
            dfs(neighbor)
        result.append(node)
    for node in graph:
        dfs(node)
    return result[::-1]


def is_valid_topological_order(graph: dict, order: list) -> bool:
    """Helper: verify that for every edge u -> v, u appears before v in order."""
    position = {node: i for i, node in enumerate(order)}
    for node, neighbors in graph.items():
        if node not in position:
            return False
        for neighbor in neighbors:
            if neighbor not in position:
                return False
            if position[node] >= position[neighbor]:
                return False
    return True


