class TestHappyPath:
    def test_simple_linear_chain(self):
        # A -> B -> C -> D
        graph = {"A": ["B"], "B": ["C"], "C": ["D"], "D": []}
        result = topological_sort(graph)
        assert result == ["A", "B", "C", "D"]

    def test_simple_dag(self):
        #     A
        #    / \
        #   B   C
        #    \ /
        #     D
        graph = {"A": ["B", "C"], "B": ["D"], "C": ["D"], "D": []}
        result = topological_sort(graph)
        assert is_valid_topological_order(graph, result)
        assert set(result) == {"A", "B", "C", "D"}
        assert result.index("A") < result.index("B")
        assert result.index("A") < result.index("C")
        assert result.index("B") < result.index("D")
        assert result.index("C") < result.index("D")

    def test_multiple_independent_components(self):
        # Two disjoint chains: A->B and C->D
        graph = {"A": ["B"], "B": [], "C": ["D"], "D": []}
        result = topological_sort(graph)
        assert is_valid_topological_order(graph, result)
        assert set(result) == {"A", "B", "C", "D"}

    def test_classic_course_prerequisites(self):
        # Common textbook example
        graph = {
            "shirt": ["belt", "tie"],
            "tie": ["jacket"],
            "belt": ["jacket"],
            "jacket": [],
            "pants": ["belt", "shoes"],
            "underwear": ["pants", "shoes"],
            "socks": ["shoes"],
            "shoes": [],
        }
        result = topological_sort(graph)
        assert is_valid_topological_order(graph, result)
        assert len(result) == len(graph)

    def test_diamond_dependency(self):
        graph = {1: [2, 3], 2: [4], 3: [4], 4: []}
        result = topological_sort(graph)
        assert is_valid_topological_order(graph, result)
        assert result[0] == 1
        assert result[-1] == 4

    def test_integer_nodes(self):
        graph = {1: [2], 2: [3], 3: []}
        result = topological_sort(graph)
        assert result == [1, 2, 3]


