class TestEdgeCases:
    def test_empty_graph(self):
        assert topological_sort({}) == []

    def test_single_node_no_edges(self):
        assert topological_sort({"A": []}) == ["A"]

    def test_single_node_self_loop(self):
        # Function does not raise on self loops because of the `visited` guard.
        # It still returns the node, even though the graph isn't a strict DAG.
        result = topological_sort({"A": ["A"]})
        assert result == ["A"]

    def test_all_isolated_nodes(self):
        graph = {"A": [], "B": [], "C": []}
        result = topological_sort(graph)
        assert set(result) == {"A", "B", "C"}
        assert len(result) == 3

    def test_node_referenced_but_not_a_key(self):
        # B is a neighbor but not present as a key in the graph dict.
        # graph.get(node, []) handles this gracefully.
        graph = {"A": ["B"]}
        result = topological_sort(graph)
        assert is_valid_topological_order(graph, result)
        assert result.index("A") < result.index("B")
        assert set(result) == {"A", "B"}

    def test_duplicate_edges(self):
        # Same neighbor listed multiple times should not duplicate output.
        graph = {"A": ["B", "B", "B"], "B": []}
        result = topological_sort(graph)
        assert result == ["A", "B"]

    def test_tuple_nodes(self):
        graph = {(0, 0): [(0, 1)], (0, 1): []}
        result = topological_sort(graph)
        assert result == [(0, 0), (0, 1)]

    def test_large_linear_chain(self):
        n = 1000
        graph = {i: [i + 1] for i in range(n)}
        graph[n] = []
        result = topological_sort(graph)
        assert result == list(range(n + 1))

    def test_result_contains_all_nodes(self):
        graph = {"A": ["B", "C"], "B": ["D"], "C": [], "D": []}
        result = topological_sort(graph)
        assert sorted(result) == sorted(graph.keys())


